#include<bits/stdc++.h>
using namespace std;
int a[10010];
int n,m;
vector<int> mp[10010],mp1[10010];
int in[10010];
stack<int> s;
bool instk[10010];
int dfn[10010],f[10010],low[10010],scccnt,scc[10010],siz[10010],val[10010],dfncnt;
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    instk[x]=true;
    s.push(x);
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            s.pop();
            scc[top]=scccnt;
            siz[scccnt]++;
            val[scccnt]+=a[top];
            instk[top]=false;
        }while(top!=x);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j:mp[i])
        {
            if(scc[i]!=scc[j])
            {
                in[scc[j]]++;
                mp1[scc[i]].push_back(scc[j]);
            }
        }
    }
    queue<int> q;
    for(int i=1;i<=scccnt;i++)
    {
        if(in[i]==0)
        {
            q.push(i);
            f[i]=val[i];
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i:mp1[t])
        {
            in[i]--;
            f[i]=max(f[i],f[t]+val[i]);
            if(in[i]==0)
            {
                q.push(i);
            }
        }
    }
    int ans=0;
    for(int i=1;i<=scccnt;i++)
    {
        ans=max(ans,f[i]);
    }
    printf("%d",ans);
    return 0;
}
